import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"터무니없는 스킬로 이세계 방랑 밥","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/animations/터무니없는-스킬로-이세계-방랑-밥.md","filePath":"outta-space/knowledge/animations/터무니없는-스킬로-이세계-방랑-밥.md"}'),_={name:"outta-space/knowledge/animations/터무니없는-스킬로-이세계-방랑-밥.md"};function n(i,a,l,s,d,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="터무니없는-스킬로-이세계-방랑-밥" tabindex="-1">터무니없는 스킬로 이세계 방랑 밥 <a class="header-anchor" href="#터무니없는-스킬로-이세계-방랑-밥" aria-label="Permalink to &quot;터무니없는 스킬로 이세계 방랑 밥&quot;">​</a></h1><h2 id="_1-이야기와-전개" tabindex="-1">1. 이야기와 전개 <a class="header-anchor" href="#_1-이야기와-전개" aria-label="Permalink to &quot;1. 이야기와 전개&quot;">​</a></h2><p>인터넷 쇼핑 스킬을 가진 주인공이 이세계에서 음식을 만들며 살아가는 이세계 판타지물이다.</p><p>아무 생각 없이 보기 좋다. 주인공 파티가 지나치게 강하고, 주인공 역시 사기적인 능력을 가지고 있어 위험 요소나 긴장감은 거의 없다.</p><h2 id="_2-캐릭터와-감정선" tabindex="-1">2. 캐릭터와 감정선 <a class="header-anchor" href="#_2-캐릭터와-감정선" aria-label="Permalink to &quot;2. 캐릭터와 감정선&quot;">​</a></h2><p>캐릭터성은 가볍고 명확하다. 사역마들의 성격과 디자인이 잘 뽑힌 편이다.</p><p>드라 짱은 취향에 맞는 캐릭터였고, 페르는 복실복실한 매력이 있다. 캐릭터의 깊이보다는 편하게 보는 귀여움과 조합의 재미가 중심이다.</p><h2 id="_3-작화와-영상미" tabindex="-1">3. 작화와 영상미 <a class="header-anchor" href="#_3-작화와-영상미" aria-label="Permalink to &quot;3. 작화와 영상미&quot;">​</a></h2><p>음식 작화가 뛰어난 편이다. 주인공이 인터넷 쇼핑으로 레토르트나 조미료를 많이 사기 때문에, 대부분 “아는 맛” 중심으로 나오는 점이 재미있었다.</p><h2 id="_4-음악과-성우-연기" tabindex="-1">4. 음악과 성우 연기 <a class="header-anchor" href="#_4-음악과-성우-연기" aria-label="Permalink to &quot;4. 음악과 성우 연기&quot;">​</a></h2><p>가벼운 이세계 일상물 분위기를 무난하게 살린다. 큰 긴장감보다는 편안한 흐름을 유지하는 쪽에 가깝다.</p><h2 id="_5-주제와-여운" tabindex="-1">5. 주제와 여운 <a class="header-anchor" href="#_5-주제와-여운" aria-label="Permalink to &quot;5. 주제와 여운&quot;">​</a></h2><p>깊은 주제보다는 편하게 힐링하는 작품이다.</p><p>『던전밥』과 비교하면 메뉴 구성이나 스토리는 던전밥이 더 우세하지만, 작화나 캐릭터성은 이 작품이 더 취향에 맞을 수 있다.</p><p>한 줄 평: 긴장감은 없지만, 음식 작화와 사역마 캐릭터를 편하게 즐기기 좋은 이세계 밥 애니메이션.</p>',15)])])}const u=e(_,[["render",n]]);export{c as __pageData,u as default};
